import { sqliteTable, text, integer, real } from 'drizzle-orm/sqlite-core';

// ── Auth / Staff ─────────────────────────────────────────────────────────────
// Mirrors Clerk users; clerkId is the Clerk user ID
export const users = sqliteTable('users', {
  id: text('id').primaryKey(),            // Clerk user ID
  email: text('email').notNull().unique(),
  name: text('name').notNull().default(''),
  role: text('role').notNull().default('staff'), // 'admin' | 'staff' | 'driver'
  active: integer('active', { mode: 'boolean' }).notNull().default(true),
  // When true, this user appears in driver lists and is allowed to use the
  // driver app even if role is not 'driver' (e.g. Seamus is role='admin' but
  // also drives). Implicitly true for role='driver' users.
  canDrive: integer('can_drive', { mode: 'boolean' }).notNull().default(false),
  phone: text('phone'),
  address: text('address'),
  vehicleInfo: text('vehicle_info'),
  registrationNumber: text('registration_number'),
  licenseNumber: text('license_number'),
  nextOfKin: text('next_of_kin'),         // JSON: { name, phone }
  zones: text('zones').notNull().default('[]'), // JSON: string[] of postcode prefixes
  startAddress: text('start_address'),        // route starting point for drivers
  createdAt: integer('created_at').notNull(),
  updatedAt: integer('updated_at').notNull(),
});

// ── Customers ─────────────────────────────────────────────────────────────────
// Explicit Clerk-to-staff links. A staff member can end up with more than one
// Clerk id over time (test/live drift, recreated Clerk user, customer/admin
// split identity). Keep the app's staff user stable and map auth ids here.
export const staffAuthLinks = sqliteTable('staff_auth_links', {
  id: text('id').primaryKey(),
  userId: text('user_id').notNull().references(() => users.id),
  clerkId: text('clerk_id').notNull().unique(),
  email: text('email').notNull(),
  source: text('source').notNull().default('manual'),
  active: integer('active', { mode: 'boolean' }).notNull().default(true),
  createdAt: integer('created_at').notNull(),
  updatedAt: integer('updated_at').notNull(),
});

// Support-code trace for auth failures. These rows are diagnostic only: they
// help support match a user-facing code to the rejected Clerk session without
// exposing tokens or secrets.
export const authFailures = sqliteTable('auth_failures', {
  id: text('id').primaryKey(),
  supportId: text('support_id').notNull().unique(),
  code: text('code').notNull(),
  clerkId: text('clerk_id'),
  issuer: text('issuer'),
  tokenEmails: text('token_emails').notNull().default('[]'),
  path: text('path').notNull().default(''),
  userAgent: text('user_agent').notNull().default(''),
  createdAt: integer('created_at').notNull(),
});

// Privacy-safe website analytics for the admin Insights tab. The session hash
// rotates daily and no IP address, name, email, or raw user agent is stored.
export const pageEvents = sqliteTable('page_events', {
  id: text('id').primaryKey(),
  path: text('path').notNull(),
  itemId: text('item_id'),
  sessionHash: text('session_hash').notNull(),
  referrerHost: text('referrer_host'),
  countryCode: text('country_code'),
  deviceType: text('device_type'),
  browser: text('browser'),
  os: text('os'),
  createdAt: integer('created_at').notNull(),
});

// Customers
export const customers = sqliteTable('customers', {
  id: text('id').primaryKey(),            // UUID
  email: text('email').notNull().unique(),
  phone: text('phone').notNull().default(''),
  name: text('name').notNull(),
  addresses: text('addresses').notNull().default('[]'), // JSON: Address[]
  accountType: text('account_type').notNull().default('registered'), // 'registered' | 'guest'
  orderCount: integer('order_count').notNull().default(0),
  totalSpent: integer('total_spent').notNull().default(0), // cents
  blacklisted: integer('blacklisted', { mode: 'boolean' }).notNull().default(false),
  blacklistReason: text('blacklist_reason'),
  notes: text('notes').notNull().default(''),
  clerkId: text('clerk_id').unique(),     // set when customer creates an account
  squareCustomerId: text('square_customer_id'),   // Square customer ID for card-on-file payments
  squareCardId: text('square_card_id'),           // saved card ID for recurring charges
  squareCardLast4: text('square_card_last4'),     // last 4 digits for display
  squareCardBrand: text('square_card_brand'),     // VISA, MASTERCARD, etc.
  createdAt: integer('created_at').notNull(),
  updatedAt: integer('updated_at').notNull(),
});

// ── Suppliers ─────────────────────────────────────────────────────────────────
export const suppliers = sqliteTable('suppliers', {
  id: text('id').primaryKey(),
  name: text('name').notNull(),
  contactName: text('contact_name').notNull().default(''),
  phone: text('phone').notNull().default(''),
  email: text('email').notNull().default(''),
  abn: text('abn').notNull().default(''),
  paymentTerms: text('payment_terms').notNull().default(''),
  notes: text('notes').notNull().default(''),
  active: integer('active', { mode: 'boolean' }).notNull().default(true),
  createdAt: integer('created_at').notNull(),
});

// ── Products ──────────────────────────────────────────────────────────────────
export const products = sqliteTable('products', {
  id: text('id').primaryKey(),
  name: text('name').notNull(),
  description: text('description').notNull().default(''),
  category: text('category').notNull(),  // 'beef' | 'lamb' | 'pork' | 'chicken' | 'packs'
  isMeatPack: integer('is_meat_pack', { mode: 'boolean' }).notNull().default(false),
  pricePerKg: integer('price_per_kg'),   // cents/kg, null for packs
  fixedPrice: integer('fixed_price'),    // cents, null for loose cuts
  weightOptions: text('weight_options'), // JSON: number[] (grams), null for packs
  packContents: text('pack_contents'),
  imageUrl: text('image_url').notNull().default(''),
  stockOnHand: real('stock_on_hand').notNull().default(0), // kg or units
  minThreshold: real('min_threshold').notNull().default(0),
  maxStock: real('max_stock'),
  supplierId: text('supplier_id').references(() => suppliers.id),
  active: integer('active', { mode: 'boolean' }).notNull().default(true),
  displayOrder: integer('display_order').notNull().default(0),
  gstApplicable: integer('gst_applicable', { mode: 'boolean' }).notNull().default(true),
  seasonalStart: integer('seasonal_start'), // unix ms
  seasonalEnd: integer('seasonal_end'),
  cookingTips: text('cooking_tips'),
  createdAt: integer('created_at').notNull(),
  updatedAt: integer('updated_at').notNull(),
});

// ── Delivery Days ─────────────────────────────────────────────────────────────
export const deliveryDays = sqliteTable('delivery_days', {
  id: text('id').primaryKey(),
  date: integer('date').notNull(),       // unix ms (start of day)
  dayOfWeek: integer('day_of_week').notNull(), // 0=Sun
  active: integer('active', { mode: 'boolean' }).notNull().default(true),
  frozen: integer('frozen', { mode: 'boolean' }).notNull().default(false),
  cutoffTime: integer('cutoff_time').notNull(), // unix ms
  maxOrders: integer('max_orders').notNull().default(50),
  orderCount: integer('order_count').notNull().default(0),
  notes: text('notes'),
  routeGenerated: integer('route_generated', { mode: 'boolean' }).notNull().default(false),
  routeGeneratedAt: integer('route_generated_at'),
  deliveryWindowStart: text('delivery_window_start').default('09:00'), // HH:MM 24-hr
  routeStartAddress: text('route_start_address'),
  routeStartLat: real('route_start_lat'),
  routeStartLng: real('route_start_lng'),
  routeFinishAddress: text('route_finish_address'),
  routeFinishLat: real('route_finish_lat'),
  routeFinishLng: real('route_finish_lng'),
  driverUid: text('driver_uid').references(() => users.id),
  zones: text('zones').default(''),            // comma-separated area names e.g. "Rockhampton, Yeppoon, Biloela"
  type: text('type').notNull().default('delivery'),  // 'delivery' | 'pickup'
  marketLocation: text('market_location'),           // e.g. "Clinton Markets, 123 Main St"
  runStartedAt: integer('run_started_at'),
  runCompletedAt: integer('run_completed_at'),
  stockPoolId: text('stock_pool_id'),  // if set, this day shares stock allocations from another day
  createdAt: integer('created_at').notNull(),
});

// ── Orders ────────────────────────────────────────────────────────────────────
export const orders = sqliteTable('orders', {
  id: text('id').primaryKey(),
  customerId: text('customer_id').notNull().references(() => customers.id),
  customerEmail: text('customer_email').notNull(),
  customerName: text('customer_name').notNull(),
  customerPhone: text('customer_phone').notNull().default(''),
  items: text('items').notNull(),        // JSON: OrderItem[]
  subtotal: integer('subtotal').notNull(),        // cents
  deliveryFee: integer('delivery_fee').notNull(), // cents
  gst: integer('gst').notNull(),                  // cents
  total: integer('total').notNull(),              // cents
  promoCode: text('promo_code'),
  promoDiscount: integer('promo_discount').notNull().default(0), // cents
  status: text('status').notNull().default('pending_payment'),
  deliveryDayId: text('delivery_day_id').notNull().references(() => deliveryDays.id),
  deliveryAddress: text('delivery_address').notNull(), // JSON: Address
  fulfillmentType: text('fulfillment_type').notNull().default('delivery'), // 'delivery' | 'pickup'
  postcodeZone: text('postcode_zone').notNull().default(''),
  paymentIntentId: text('payment_intent_id').notNull().default(''),
  paymentProvider: text('payment_provider').notNull().default('stripe'),
  // Default is 'pending_payment', not 'paid' — see migration 0004. The old
  // 'paid' default was fail-OPEN: any code path that omitted paymentStatus
  // would silently confirm the order, which is how we ended up shipping
  // $2,210 of unpaid subscription boxes.
  paymentStatus: text('payment_status').notNull().default('pending_payment'),
  notes: text('notes'),
  internalNotes: text('internal_notes'),
  proofUrl: text('proof_url'),
  packedAt: integer('packed_at'),
  packedBy: text('packed_by'),
  createdAt: integer('created_at').notNull(),
  updatedAt: integer('updated_at').notNull(),
});

// ── Delivery Runs ─────────────────────────────────────────────────────────────
// A "run" is a geographic grouping of stops for one driver on one delivery day.
// One delivery day can have multiple runs (e.g. Rockhampton + Gladstone).
export const deliveryRuns = sqliteTable('delivery_runs', {
  id: text('id').primaryKey(),
  deliveryDayId: text('delivery_day_id').notNull().references(() => deliveryDays.id),
  name: text('name').notNull(),           // e.g. "Rockhampton North"
  zone: text('zone'),                     // postcode zone label
  color: text('color').notNull().default('#1B3A2E'), // hex for map/UI
  driverUid: text('driver_uid').references(() => users.id),
  status: text('status').notNull().default('pending'), // 'pending'|'in_progress'|'completed'
  sequence: integer('sequence').notNull().default(0),
  notes: text('notes'),
  createdAt: integer('created_at').notNull(),
});

// ── Stops ─────────────────────────────────────────────────────────────────────
export const stops = sqliteTable('stops', {
  id: text('id').primaryKey(),
  orderId: text('order_id'),  // nullable for manual stops
  deliveryDayId: text('delivery_day_id').notNull(),
  runId: text('run_id'),     // nullable; null = unassigned
  customerId: text('customer_id'),  // nullable for manual stops
  customerName: text('customer_name').notNull(),
  customerPhone: text('customer_phone').notNull().default(''),
  address: text('address').notNull(),    // JSON: Address
  items: text('items').notNull(),        // JSON: OrderItem[]
  sequence: integer('sequence').notNull().default(0),
  status: text('status').notNull().default('pending'),
  estimatedArrival: integer('estimated_arrival'),
  completedAt: integer('completed_at'),
  proofUrl: text('proof_url'),
  lat: real('lat'),
  lng: real('lng'),
  customerNote: text('customer_note'),
  driverNote: text('driver_note'),
  flagReason: text('flag_reason'),
  createdAt: integer('created_at').notNull(),
});

// ── Driver Sessions ───────────────────────────────────────────────────────────
export const driverSessions = sqliteTable('driver_sessions', {
  id: text('id').primaryKey(),
  driverUid: text('driver_uid').notNull().references(() => users.id),
  driverName: text('driver_name').notNull(),
  deliveryDayId: text('delivery_day_id').notNull().references(() => deliveryDays.id),
  active: integer('active', { mode: 'boolean' }).notNull().default(true),
  startedAt: integer('started_at').notNull(),
  completedAt: integer('completed_at'),
  lastLat: real('last_lat').notNull().default(0),
  lastLng: real('last_lng').notNull().default(0),
  lastUpdated: integer('last_updated').notNull(),
  breadcrumb: text('breadcrumb').notNull().default('[]'), // JSON: {lat,lng,ts}[]
  totalStops: integer('total_stops').notNull().default(0),
  completedStops: integer('completed_stops').notNull().default(0),
  flaggedStops: integer('flagged_stops').notNull().default(0),
});

// ── Stock Movements ───────────────────────────────────────────────────────────
export const stockMovements = sqliteTable('stock_movements', {
  id: text('id').primaryKey(),
  productId: text('product_id').notNull().references(() => products.id),
  productName: text('product_name').notNull(),
  type: text('type').notNull(), // 'sale' | 'adjustment' | 'stocktake_correction' | 'wastage' | 'supplier_delivery'
  qty: real('qty').notNull(),   // positive = in, negative = out
  unit: text('unit').notNull(), // 'kg' | 'units'
  reason: text('reason'),
  orderId: text('order_id'),
  supplierId: text('supplier_id'),
  stocktakeSessionId: text('stocktake_session_id'),
  createdBy: text('created_by').notNull(),
  createdAt: integer('created_at').notNull(),
});

// ── Delivery Day Stock Allocations ────────────────────────────────────────────
export const deliveryDayStock = sqliteTable('delivery_day_stock', {
  id: text('id').primaryKey(),
  deliveryDayId: text('delivery_day_id').notNull().references(() => deliveryDays.id),
  productId: text('product_id').notNull().references(() => products.id),
  productName: text('product_name').notNull().default(''),
  allocated: real('allocated').notNull().default(0),  // kg or units allocated for this day
  sold: real('sold').notNull().default(0),            // kg or units sold so far
  createdAt: integer('created_at').notNull(),
});

// ── Stocktake Sessions ────────────────────────────────────────────────────────
export const stocktakeSessions = sqliteTable('stocktake_sessions', {
  id: text('id').primaryKey(),
  date: integer('date').notNull(),
  status: text('status').notNull().default('in_progress'), // 'in_progress' | 'completed'
  categories: text('categories').notNull().default('[]'), // JSON: string[]
  items: text('items').notNull().default('[]'),           // JSON: StocktakeItem[]
  totalVarianceKg: real('total_variance_kg').notNull().default(0),
  totalVarianceValue: integer('total_variance_value').notNull().default(0), // cents
  approvedBy: text('approved_by'),
  approvedAt: integer('approved_at'),
  createdBy: text('created_by').notNull(),
  createdAt: integer('created_at').notNull(),
});

// ── Promo Codes ──────────────────────────────────────────────────────────────
export const promoCodes = sqliteTable('promo_codes', {
  id: text('id').primaryKey(),
  code: text('code').notNull(),              // e.g. 'WELCOME10'
  type: text('type').notNull().default('percentage'),  // 'percentage' | 'fixed'
  value: integer('value').notNull(),          // percentage (10 = 10%) or cents (1000 = $10)
  minOrder: integer('min_order').default(0),  // minimum order subtotal in cents
  maxUses: integer('max_uses'),              // null = unlimited
  usedCount: integer('used_count').notNull().default(0),
  expiresAt: integer('expires_at'),          // unix ms, null = never
  deliveryDayIds: text('delivery_day_ids'),  // JSON array of delivery_day ids; null = all days
  active: integer('active', { mode: 'boolean' }).notNull().default(true),
  createdAt: integer('created_at').notNull(),
});

// ── Subscriptions ─────────────────────────────────────────────────────────────
export const subscriptions = sqliteTable('subscriptions', {
  id: text('id').primaryKey(),
  customerId: text('customer_id').references(() => customers.id),
  email: text('email').notNull(),
  boxId: text('box_id').notNull(),
  boxName: text('box_name').notNull(),
  alternateBoxId: text('alternate_box_id'),
  alternateBoxName: text('alternate_box_name'),
  nextIsAlternate: integer('next_is_alternate', { mode: 'boolean' }).notNull().default(false),
  frequency: text('frequency').notNull(), // 'weekly' | 'fortnightly' | 'monthly'
  status: text('status').notNull().default('active'), // 'active' | 'paused' | 'cancelled'
  lastOrderGeneratedAt: integer('last_order_generated_at'), // unix ms — when the last order was auto-created
  createdAt: integer('created_at').notNull(),
  updatedAt: integer('updated_at').notNull(),
});

// ── Push Subscriptions ────────────────────────────────────────────────────────
export const pushSubscriptions = sqliteTable('push_subscriptions', {
  id: text('id').primaryKey(),
  customerId: text('customer_id').notNull().references(() => customers.id),
  endpoint: text('endpoint').notNull().unique(),
  p256dh: text('p256dh').notNull(),
  auth: text('auth').notNull(),
  createdAt: integer('created_at').notNull(),
});

// ── Notification Log ──────────────────────────────────────────────────────────
export const notifications = sqliteTable('notifications', {
  id: text('id').primaryKey(),
  orderId: text('order_id'),
  customerId: text('customer_id'),
  type: text('type').notNull(), // 'order_confirmation' | 'day_before' | 'out_for_delivery' | etc.
  status: text('status').notNull().default('sent'), // 'sent' | 'failed'
  recipientEmail: text('recipient_email').notNull(),
  resendId: text('resend_id'),
  error: text('error'),
  sentAt: integer('sent_at').notNull(),
});

// ── Webhook idempotency ───────────────────────────────────────────────────────
// Records the IDs of webhooks we've already processed (Stripe / Square /
// Square Payment Link, etc.) so retries don't double-deduct stock or send
// duplicate emails. The `id` column stores the upstream event id (e.g.
// `evt_1ABC...`); insert-or-fail at the start of each handler is the dedup.
export const processedWebhooks = sqliteTable('processed_webhooks', {
  id: text('id').primaryKey(),
  source: text('source').notNull(), // 'stripe' | 'square'
  receivedAt: integer('received_at').notNull(),
});

// ── Audit Log ─────────────────────────────────────────────────────────────────
export const auditLog = sqliteTable('audit_log', {
  id: text('id').primaryKey(),
  action: text('action').notNull(),
  entity: text('entity').notNull(),
  entityId: text('entity_id').notNull(),
  before: text('before').notNull().default('{}'), // JSON
  after: text('after').notNull().default('{}'),   // JSON
  adminUid: text('admin_uid').notNull(),
  adminEmail: text('admin_email').notNull(),
  timestamp: integer('timestamp').notNull(),
});

// ── Reels (admin-managed Facebook reel embeds for storefront) ────────────────
export const reels = sqliteTable('reels', {
  id: text('id').primaryKey(),
  title: text('title').notNull(),
  subtitle: text('subtitle').notNull().default(''),
  fbUrl: text('fb_url').notNull(),
  thumbnailUrl: text('thumbnail_url'),
  displayOrder: integer('display_order').notNull().default(0),
  active: integer('active', { mode: 'boolean' }).notNull().default(true),
  createdAt: integer('created_at').notNull(),
  updatedAt: integer('updated_at').notNull(),
});

// ── Config (key/value store for BusinessConfig, DeliveryZones, etc.) ──────────
export const config = sqliteTable('config', {
  key: text('key').primaryKey(),
  value: text('value').notNull(), // JSON
  updatedAt: integer('updated_at').notNull(),
  updatedBy: text('updated_by').notNull().default('system'),
});

// ── Receipt-capture mini-app ─────────────────────────────────────────────────
// Built so Seamus can snap receipts on his phone instead of being chased for
// them by his bookkeeper. Multi-tenant from day one so this is reusable —
// businesses + business_members let one user belong to one or more businesses;
// receipts are scoped per business so a second tenant can be added without
// migrating data. Today only O'Connor Agriculture exists (seeded by migration
// 0003).
export const businesses = sqliteTable('businesses', {
  id: text('id').primaryKey(),                                        // UUID-ish
  name: text('name').notNull(),                                       // e.g. "O'Connor Agriculture"
  slug: text('slug').notNull().unique(),                              // url-safe identifier
  hubdocEmail: text('hubdoc_email'),                                  // bookkeeper's upload inbox — receipts auto-forwarded here
  active: integer('active', { mode: 'boolean' }).notNull().default(true),
  createdAt: integer('created_at').notNull(),
  updatedAt: integer('updated_at').notNull(),
});

// Junction so one user can belong to multiple businesses (Steve helps Seamus
// today, might help someone else tomorrow). UNIQUE on (business_id, user_id)
// prevents duplicate memberships.
export const businessMembers = sqliteTable('business_members', {
  id: text('id').primaryKey(),
  businessId: text('business_id').notNull().references(() => businesses.id),
  userId: text('user_id').notNull().references(() => users.id),
  role: text('role').notNull().default('owner'),  // 'owner' | 'member' | 'bookkeeper'
  createdAt: integer('created_at').notNull(),
});

// One receipt = one photo. Optional manual fields (amount, merchant, notes)
// the user or bookkeeper can fill in later. hubdocForwardedAt is set when the
// auto-email to the business's Hubdoc inbox succeeds — failures stash a
// short reason in hubdocForwardError so the admin UI can show "retry".
export const receipts = sqliteTable('receipts', {
  id: text('id').primaryKey(),
  businessId: text('business_id').notNull().references(() => businesses.id),
  capturedByUid: text('captured_by_uid').notNull().references(() => users.id),
  photoKey: text('photo_key').notNull(),                 // R2 object key, lives under receipts/<uuid>.<ext>
  contentType: text('content_type').notNull().default('image/jpeg'),
  notes: text('notes'),                                  // optional user note ("fuel for truck", "feed pickup")
  amountCents: integer('amount_cents'),                  // optional manual entry
  merchant: text('merchant'),                            // optional manual entry
  hubdocForwardedAt: integer('hubdoc_forwarded_at'),     // set when auto-email succeeds
  hubdocForwardError: text('hubdoc_forward_error'),      // last failure reason if any
  capturedAt: integer('captured_at').notNull(),
  createdAt: integer('created_at').notNull(),
  updatedAt: integer('updated_at').notNull(),
});
